#include <stdio.h>
#include <stdlib.h>

// Structure to represent a graph
typedef struct {
    int V;
    int **adj;
} Graph;

// Function to create a graph
Graph* createGraph(int V) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->V = V;
    graph->adj = (int**) malloc(V * sizeof(int*));
    for (int i = 0; i < V; i++) {
        graph->adj[i] = (int*) malloc(V * sizeof(int));
        for (int j = 0; j < V; j++) {
            graph->adj[i][j] = 0;
        }
    }
    return graph;
}

// Function to perform topological sort
void topoSort(Graph* graph, int* indegree) {
    int* queue = (int*) malloc(graph->V * sizeof(int));
    int front = 0, rear = 0;
    for (int i = 0; i < graph->V; i++) {
        if (indegree[i] == 0) {
            queue[rear++] = i;
        }
    }
    while (front < rear) {
        int node = queue[front++];
        printf("%c ", node + 'a');
        for (int i = 0; i < graph->V; i++) {
            if (graph->adj[node][i] == 1) {
                indegree[i]--;
                if (indegree[i] == 0) {
                    queue[rear++] = i;
                }
            }
        }
    }
}

// Function to find the order of characters
void findOrder(char** dict, int N, int K) {
    Graph* graph = createGraph(K);
    int* indegree = (int*) malloc(K * sizeof(int));
    for (int i = 0; i < K; i++) {
        indegree[i] = 0;
    }
    for (int i = 0; i < N - 1; i++) {
        char* s1 = dict[i];
        char* s2 = dict[i + 1];
        int len = (strlen(s1) < strlen(s2)) ? strlen(s1) : strlen(s2);
        for (int ptr = 0; ptr < len; ptr++) {
            if (s1[ptr] != s2[ptr]) {
                graph->adj[s1[ptr] - 'a'][s2[ptr] - 'a'] = 1;
                indegree[s2[ptr] - 'a']++;
                break;
            }
        }
    }
    topoSort(graph, indegree);
}

int main() {
    int N = 5, K = 4;
    char* dict[] = {"baa", "abcd", "abca", "cab", "cad"};
    findOrder(dict, N, K);
    return 0;
}

