import java.util.*;

// Class to represent the solution
public class Solution {
    // Function to perform Topological Sort (Kahn's Algorithm - BFS approach)
    private List<Integer> topoSort(int V, List<List<Integer>> adj) {
        // Array to keep track of indegree (number of incoming edges) of each node
        int[] indegree = new int[V];

        // Calculate indegree for each vertex
        for (int i = 0; i < V; i++) {
            for (int neighbor : adj.get(i)) {
                indegree[neighbor]++;
            }
        }

        // Queue to store nodes with indegree = 0 (i.e., nodes that can be processed first)
        Queue<Integer> q = new LinkedList<>();
        for (int i = 0; i < V; i++) {
            if (indegree[i] == 0) {
                q.add(i);
            }
        }

        // List to store topological order
        List<Integer> topo = new ArrayList<>();

        // Process the queue
        while (!q.isEmpty()) {
            int node = q.poll();
            topo.add(node); // Add node to result

            // Decrease indegree of its neighbors
            for (int neighbor : adj.get(node)) {
                indegree[neighbor]--;
                if (indegree[neighbor] == 0) {
                    q.add(neighbor);
                }
            }
        }

        return topo;
    }

    // Function to find the order of characters
    public String findOrder(String[] dict, int N, int K) {
        // Adjacency list for graph representation
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < K; i++) {
            adj.add(new ArrayList<>());
        }

        // Build graph by comparing adjacent words in dictionary
        for (int i = 0; i < N - 1; i++) {
            String s1 = dict[i];
            String s2 = dict[i + 1];
            int len = Math.min(s1.length(), s2.length());

            for (int ptr = 0; ptr < len; ptr++) {
                if (s1.charAt(ptr) != s2.charAt(ptr)) {
                    // Add edge s1[ptr] -> s2[ptr]
                    adj.get(s1.charAt(ptr) - 'a').add(s2.charAt(ptr) - 'a');
                    break;
                }
            }
        }

        // Perform topological sort
        List<Integer> topo = topoSort(K, adj);

        // Convert numeric representation back to characters
        StringBuilder ans = new StringBuilder();
        for (int node : topo) {
            ans.append((char)(node + 'a'));
        }

        return ans.toString();
    }

    // Driver Code
    public static void main(String[] args) {
        int N = 5, K = 4;
        String[] dict = {"baa", "abcd", "abca", "cab", "cad"};
        Solution obj = new Solution();
        String ans = obj.findOrder(dict, N, K);

        for (char ch : ans.toCharArray()) {
            System.out.print(ch + " ");
        }
        System.out.println();
    }
}

