class Solution {
    // Function to perform Topological Sort (Kahn's Algorithm - BFS)
    topoSort(V, adj) {
        // Array to store indegree of each node
        let indegree = new Array(V).fill(0);

        // Compute indegree for each vertex
        for (let u = 0; u < V; u++) {
            for (let v of adj[u]) {
                indegree[v]++;
            }
        }

        // Queue for vertices with indegree 0
        let q = [];
        for (let i = 0; i < V; i++) {
            if (indegree[i] === 0) {
                q.push(i);
            }
        }

        let topo = [];

        // Process queue
        while (q.length > 0) {
            let node = q.shift(); // dequeue
            topo.push(node);

            // Decrease indegree of neighbors
            for (let neighbor of adj[node]) {
                indegree[neighbor]--;
                if (indegree[neighbor] === 0) {
                    q.push(neighbor);
                }
            }
        }

        return topo;
    }

    // Function to find order of characters
    findOrder(dict, N, K) {
        // Create adjacency list
        let adj = new Array(K).fill(0).map(() => []);

        // Build graph by comparing adjacent words
        for (let i = 0; i < N - 1; i++) {
            let s1 = dict[i], s2 = dict[i + 1];
            let len = Math.min(s1.length, s2.length);

            for (let ptr = 0; ptr < len; ptr++) {
                if (s1[ptr] !== s2[ptr]) {
                    adj[s1.charCodeAt(ptr) - 97].push(s2.charCodeAt(ptr) - 97);
                    break;
                }
            }
        }

        // Perform topological sort
        let topo = this.topoSort(K, adj);

        // Convert indices back to characters
        let ans = "";
        for (let node of topo) {
            ans += String.fromCharCode(node + 97);
        }

        return ans;
    }
}

